from urllib.parse import urlencode, urlparse, parse_qs

def build_login_redirect(login_url: str, current_url: str, next_param: str = "next") -> str:
    parsed_login = urlparse(login_url)
    existing_query = parse_qs(parsed_login.query, keep_blank_values=True)
    existing_query[next_param] = [current_url]

    query = urlencode(existing_query, doseq=True)
    return parsed_login._replace(query=query).geturl()

def get_post_login_redirect(default_url: str, requested_next: str | None, allowed_hosts: set[str] | None = None) -> str:
    if not requested_next:
        return default_url

    parsed = urlparse(requested_next)

    if parsed.scheme or parsed.netloc:
        if not allowed_hosts or parsed.netloc not in allowed_hosts:
            return default_url

    if not requested_next.startswith("/") and not (parsed.scheme and parsed.netloc):
        return default_url

    return requested_next

